import React, { useEffect, useState } from "react";
import { LineChart, Line, XAxis, YAxis, Tooltip, Legend, ResponsiveContainer } from "recharts";
import { fetchBuses } from "./api";

export default function BusCharts() {
  const [data, setData] = useState([]);

  const getChartData = async () => {
    const res = await fetchBuses();
    if (res && res.buses) {
      const ghostCount = res.buses.filter(b => b.isGhost).length;
      const normalCount = res.buses.filter(b => !b.isGhost).length;
      const timestamp = new Date().toLocaleTimeString();
      setData(prev => [...prev, { name: timestamp, Ghost: ghostCount, Normal: normalCount }]);
    }
  };

  useEffect(() => {
    getChartData();
    const interval = setInterval(getChartData, 120000);
    return () => clearInterval(interval);
  }, []);

  return (
    <ResponsiveContainer width={400} height={300}>
      <LineChart data={data}>
        <XAxis dataKey="name" />
        <YAxis />
        <Tooltip />
        <Legend />
        <Line type="monotone" dataKey="Ghost" stroke="red" />
        <Line type="monotone" dataKey="Normal" stroke="green" />
      </LineChart>
    </ResponsiveContainer>
  );
}
